import{_ as t,o as n,c as s,a3 as o}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"99. Ohs Risk Management","description":"","frontmatter":{"title":"99. Ohs Risk Management","eba":"Nurses and Midwives 2024-2028","topics":["consultation","ohs"]},"headers":[],"relativePath":"ebas/nurses-midwives/ohs/99-ohs-risk-management.md","filePath":"ebas/nurses-midwives/ohs/99-ohs-risk-management.md"}'),i={name:"ebas/nurses-midwives/ohs/99-ohs-risk-management.md"};function a(r,e,l,p,h,c){return n(),s("div",null,[...e[0]||(e[0]=[o('<h1 id="_99-ohs-risk-management" tabindex="-1">99. Ohs Risk Management <a class="header-anchor" href="#_99-ohs-risk-management" aria-label="Permalink to &quot;99. Ohs Risk Management&quot;">​</a></h1><p><strong>99.1</strong> Those covered by this Agreement will take a proactive approach to the prevention and management of workplace injuries to the highest level of protection reasonably practicable in the circumstances, and to the achievement of a reduction in workplace injuries through the implementation of risk management systems incorporating hazard identification, risk assessment and control, and safe work practices.</p><p><strong>99.2</strong> Those covered by this Agreement recognise that consultation with nurses, midwives and their representatives is crucial to achieving a healthy and safe work environment. To this end, Employers will consult with nurses, midwives and their representatives around matters relating to health and safety in the workplace.</p><p><strong>99.3</strong> Employers will implement the hierarchy of controls to control hazards and will eliminate the hazard at the source wherever practicable.</p><p><strong>99.4</strong> Central Building Consultative Committee</p><p>Note: Nothing in this clause 99.4 limits the Employer’s obligations to consult with HSRs under the OHS Act</p><p><strong>(a)</strong> Where an employer is proposing to undertake construction of a new or significantly changed work area or areas, including construction of a new facility, the employer will establish a central building consultative committee for the purpose of consulting with HSRs and the Unions.</p><p><strong>(b)</strong> The Employer will notify the unions in writing, and invite the unions to nominate representatives to participate in the central building consultative committee (CBCC). The Employer will make available to the CBCC the information to enable the CBCC to fulfil the intention of this provision.</p><p><strong>(c)</strong> The CBCC will be responsible for the consultation process. This will include the design elements of the proposed construction from an occupational health and safety perspective.</p><p><strong>(d)</strong> This committee will include representatives from the Employer, HSRs from relevant workplaces, the Union and other members as relevant, to proactively discuss, review proposals and plans, and provide input for consideration.</p><p><strong>(e)</strong> Consultation will include:</p><p><strong>(i)</strong> the provision of the building plans once the Employer has the capacity to do so; and</p><p><strong>(ii)</strong> walkthroughs of the site at key stages of development.</p><p><strong>(f)</strong> The Employer will notify the Union of the expected timeline for the events listed in subclause 99.4(e) as soon as possible to facilitate participation. The Unions will cooperate to ensure such consultation occurs without undue delay to the construction and/or commissioning.</p><p><strong>99.5</strong> This Agreement recognises that hazards include, but are not limited to:</p><p><strong>(a)</strong> safe patient and manual handling;</p><p><strong>(b)</strong> occupational violence and aggression;</p><p><strong>(c)</strong> circumstances that give rise to adverse effects on psychological health, including bullying, workplace stress and fatigue;</p><p><strong>(d)</strong> unsafe design and layout of health workplaces;</p><p><strong>(e)</strong> slips, trips and falls;</p><p><strong>(f)</strong> blood borne and other infectious diseases;</p><p><strong>(g)</strong> sharps; and</p><p><strong>(h)</strong> hazardous substances.</p><p><strong>99.6</strong> Employers will ensure Nurse Managers/Supervisors receive adequate education and support to ensure the following can occur:</p><p><strong>(a)</strong> the assessment of OHS risks;</p><p><strong>(b)</strong> the undertaking of OHS incident investigations; and</p><p><strong>(c)</strong> consultation with staff over OHS issues.</p><p><strong>99.7</strong> Employers will provide information, education, training and supervision to all Employees of the Employer required to enable them to perform their work in a manner which is safe and without risks to health. This will occur on a regular basis as required to enable Employees to remain informed in relation to health and safety hazards, policies and procedures.</p><p><strong>99.8</strong> Manual Handling Incidents</p><p><strong>(a)</strong> Employers will, in consultation with HSRs:</p><p><strong>(i)</strong> identify the number of manual handling incidents/injuries over the previous 12 months;</p><p><strong>(ii)</strong> review risk control measures as required by regulation 28 of the Occupational Health and Safety Regulations 2017; and</p><p><strong>(iii)</strong> so far as is reasonably practicable, eliminate any risk of a musculoskeletal disorder associated with hazardous manual handling or, if it is not reasonably practicable to eliminate a risk of a musculoskeletal disorder associated with hazardous manual handling, the employer must reduce the risk so far as is reasonably practicable consistent with Regulation 26 of the Occupational Health and Safety Regulations 2017.</p><p><strong>(b)</strong> The considerations at (iii) above will include the frequency of safe patient and manual handling training.</p><p><strong>(c)</strong> A report regarding manual handling incidents/injuries will be provided either to the relevant OHS Committee with an invitation to the Unions or the WIC under <a href="/eba/ebas/nurses-midwives/union-matters/80-union-matters.html">clause 80</a>.</p><p>Plain language terms: risk assessment, hazard control.</p>',36)])])}const u=t(i,[["render",a]]);export{g as __pageData,u as default};
